### Option 2: Generate a 3D House using Blender (Python Script)

If you have **Blender** installed, you can use this Python script to programmatically build a house inside the Blender interface.

**Prerequisites:**
1.  Install Blender.
2.  Open Blender, go to `Edit > Preferences > Add-ons`, search for "Python", and ensure the Python interpreter is active.
3.  Open the Scripting tab in Blender, create a new text block, paste the code below, and run it.

**The Blender Python Code:**

```python
import bpy
import math

# Clear existing objects to start fresh
bpy.ops.object.select_all(action='SELECT')
bpy.ops.object.delete(use_global=False)

# Create a simple house
def create_house():
    # 1. Walls
    bpy.ops.mesh.primitive_cube_add(size=2, location=(0, 0, 0))
    walls = bpy.context.active_object
    walls.name = "Walls"
    walls.scale = (10, 10, 6)

    # 2. Roof (Cone)
    bpy.ops.mesh.primitive_cone_add(vertices=4, radius=8, depth=4, location=(0, 0, 8))
    roof = bpy.context.active_object
    roof.name = "Roof"
    roof.rotation_euler = (math.radians(90), 0, 0) # Rotate to point up

    # 3. Door
    bpy.ops.mesh.primitive_cube_add(size=2, location=(0, 0, 0))
    door = bpy.context.active_object
    door.name = "Door"
    door.scale = (2, 4, 0.5)
    door.location.z = 4 # Move to front face

    # 4. Ground
    bpy.ops.mesh.primitive_plane_add(size=2, location=(0, 0, -1))
    ground = bpy.context.active_object
    ground.name = "Ground"
    ground.scale = (100, 100, 1)

create_house()

# Apply a simple material to the walls
bpy.ops.object.select_all(action='DESELECT')
bpy.ops.object.select_by_type(type='MESH')
bpy.ops.object.select_all(action='SELECT')
bpy.ops.object.active_object('SELECT')

# Create a brown material
mat = bpy.data.materials.new(name="BrownWall")
mat.use_nodes = True
bsdf = mat.node_tree.nodes["Principled BSDF"]
bsdf.inputs['Base Color'].default_value = (0.54, 0.27, 0.13, 1.0) # Brown

# Assign material to walls
for obj in bpy.data.objects:
    if obj.type == 'MESH':
        if obj.data.materials:
            obj.data.materials[0] = mat
        else:
            mat_index = obj.data.materials.append(mat)
```

